import { jsx } from 'react/jsx-runtime';
import { forwardRef, useRef, useImperativeHandle } from 'react';
import { NewMaskField } from './NewMaskField.js';
import { OldMaskField } from './OldMaskField.js';

const MaskField = forwardRef(({ size = 'medium', autoComplete = 'off', inputClassName: externalInputClassName, fullWidth = false, error = false, disabled = false, dataTestId = 'TextField', isClickableAdornment = true, maskConfig, maskedInstance, onChange, onMaskRef, onComplete, ...props }, ref) => {
    const localRef = useRef(null);
    useImperativeHandle(ref, () => localRef.current);
    if (maskedInstance) {
        // OldMaskField ожидает onChange с одним аргументом (event)
        const handleOldOnChange = typeof onChange === 'function' ? onChange : undefined;
        return (jsx(OldMaskField, { ref: localRef, size: size, autoComplete: autoComplete, inputClassName: externalInputClassName, fullWidth: fullWidth, error: error, disabled: disabled, dataTestId: dataTestId, isClickableAdornment: isClickableAdornment, maskedInstance: maskedInstance, onChange: handleOldOnChange, ...props }));
    }
    // NewMaskField ожидает onChange с тремя аргументами (value, unmaskedValue, event)
    const handleNewOnChange = typeof onChange === 'function'
        ? onChange
        : undefined;
    return (jsx(NewMaskField, { ref: localRef, size: size, autoComplete: autoComplete, inputClassName: externalInputClassName, fullWidth: fullWidth, error: error, disabled: disabled, dataTestId: dataTestId, isClickableAdornment: isClickableAdornment, maskConfig: maskConfig, onChange: handleNewOnChange, onMaskRef: onMaskRef, onComplete: onComplete, ...props }));
});

export { MaskField };
